namespace sv_e1bb9412f04c445dad569b75665f552b.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_e1bb9412f04c445dad569b75665f552b.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="d-flex gap-4">
    @* ── Left Sidebar (Filters) ── *@
    <aside class="flex-shrink-0" style="width: 25%;">
        <div class="card">
            <div class="card-header fw-semibold">Filters</div>
            <div class="card-body">
                @* Categories *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }

                <hr />

                @* Price Range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label form-label-sm">Min Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="minPrice" placeholder="0" />
                </div>
                <div class="mb-2">
                    <label class="form-label form-label-sm">Max Price</label>
                    <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                           @bind="maxPrice" placeholder="Any" />
                </div>

                <hr />

                @* In Stock *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                @* Action Buttons *@
                <div class="d-grid gap-2">
                    <button class="btn btn-primary btn-sm" @onclick="ApplyFilters" disabled="@isLoading">
                        Apply Filters
                    </button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters" disabled="@isLoading">
                        Clear Filters
                    </button>
                </div>
            </div>
        </div>
    </aside>

    @* ── Main Content ── *@
    <main class="flex-grow-1" style="width: 75%;">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <span class="ms-2">Loading products…</span>
            </div>
        }
        else if (searchResult is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 text-nowrap">Sort by:</label>
                    <select class="form-select form-select-sm" style="width: auto;"
                            value="@sortBy" @onchange="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    Showing @RangeStart–@RangeEnd of @searchResult.TotalCount products
                </span>
            </div>

            @if (searchResult.Items.Count == 0)
            {
                <div class="alert alert-info text-center" role="alert">
                    No products found matching your criteria. Try adjusting your filters.
                </div>
            }
            else
            {
                @* Product Grid *@
                <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mb-4">
                    @foreach (var product in searchResult.Items)
                    {
                        <div class="col">
                            <div class="card h-100 product-card" role="button"
                                 @onclick="() => OnProductSelected(product)">
                                <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
                                     style="height: 180px;" role="img" aria-label="@product.Name">
                                    <span class="text-muted">@product.Name</span>
                                </div>
                                <div class="card-body d-flex flex-column">
                                    <h6 class="card-title">@product.Name</h6>
                                    <p class="card-text fw-bold text-primary mb-1">
                                        @product.Price.ToString("C")
                                    </p>
                                    <p class="card-text mb-2">
                                        @GetStarRating(product.Rating)
                                    </p>
                                    @if (!product.InStock)
                                    {
                                        <span class="badge bg-danger mb-2">Out of Stock</span>
                                    }
                                    <button class="btn btn-sm btn-success mt-auto"
                                            disabled="@(!product.InStock)"
                                            @onclick="() => { }" @onclick:stopPropagation="true">
                                        Add to Cart
                                    </button>
                                </div>
                            </div>
                        </div>
                    }
                </div>

                @* Pagination *@
                <nav aria-label="Product pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                    disabled="@(currentPage <= 1)">
                                Previous
                            </button>
                        </li>
                        @for (int i = 1; i <= TotalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">
                                    @pageNum
                                </button>
                            </li>
                        }
                        <li class="page-item @(currentPage >= TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                    disabled="@(currentPage >= TotalPages)">
                                Next
                            </button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </main>
</div>

@code {
    [Parameter] public EventCallback<Product> OnProductClick { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? searchResult;
    private bool isLoading = true;
    private string? errorMessage;

    private int TotalPages => searchResult is null || searchResult.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)searchResult.TotalCount / PageSize);

    private int RangeStart => searchResult is null || searchResult.TotalCount == 0
        ? 0
        : (currentPage - 1) * PageSize + 1;

    private int RangeEnd => searchResult is null || searchResult.TotalCount == 0
        ? 0
        : Math.Min(currentPage * PageSize, searchResult.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadProducts();
    }

    private async Task OnProductSelected(Product product)
    {
        await OnProductClick.InvokeAsync(product);
    }

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out, transform 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
    transform: translateY(-2px);
}

